# Category: edge_computing_security

import json
from urllib import request

def lambda_handler(event, context):
    # Read the URL from the request headers
    url = event["headers"]["X-Enrich-URL"]

    # Make an HTTP GET request to fetch the data
    response = requests.get(url)

    # Extract the JSON data from the response
    data = json.loads(response.text)

    # Forward the request to the origin with the additional data
    event["headers"]["X-Enriched-Data"] = json.dumps(data)
    return {
        "statusCode": 200,
        "body": json.dumps({"message": "Additional data fetched and forwarded to origin."}),
        "headers": event["headers"],
    }